  'category.F.name': { en: 'Investment & Real Estate', zh: '投资与房地产' },
  'category.F.desc': { en: 'Calculate sponsorship rates, time value, freelance taxes, equity dilution, mortgage payments, cap rates, rental yields, BRRR returns, and rent-vs-buy analysis.', zh: '计算赞助费率、时间价值、自由职业税务、股权稀释、按揭月供、资本化率、租金收益率、BRRR 回报和租购对比。' },
  'category.M.name': { en: 'Marketing Analytics', zh: '营销分析' },
  'category.M.desc': { en: 'Measure ROAS, LTV by channel, funnel value, cohort retention curves, email campaign ROI, and content marketing ROI for performance marketers and growth teams.', zh: '衡量 ROAS、各渠道 LTV、漏斗价值、队列留存曲线、邮件营销 ROI 和内容营销 ROI，适用于绩效营销人员和增长团队。' },
  'category.O.name': { en: 'Operations / 库存运营', zh: '运营 / 库存运营' },
  'category.O.desc': { en: 'Calculate inventory turnover, carrying cost, stockout cost, reorder point, fulfillment cost, and supplier scorecards for Shopify/Amazon FBA sellers and product-based businesses.', zh: '计算库存周转率、持有成本、缺货成本、补货点、履约成本和供应商评分卡，适用于 Shopify/Amazon FBA 卖家和实体产品业务。' },
  'category.S.name': { en: 'Sales / 销售管理', zh: '销售管理' },
  'category.S.desc': { en: 'Calculate pipeline value, sales velocity, ACV, win rate by stage, quota attainment, and pipeline coverage for B2B SaaS sales teams and RevOps.', zh: '计算销售渠道价值、销售速度、平均合同金额、各阶段赢率、指标完成率和销售渠道覆盖率，适用于 B2B SaaS 销售团队和 RevOps。' },
  'category.R.name': { en: 'Retention & Customer Success', zh: '留存与客户成功' },
  'category.R.desc': { en: 'Calculate NRR, GRR, expansion revenue, logo churn rate, customer health score, and renewal rate for mid-market B2B SaaS CSMs and RevOps leads.', zh: '计算净收入留存率、毛收入留存率、扩展收入、Logo 流失率、客户健康评分和续约率，适用于中型 B2B SaaS 的客户成功经理和 RevOps 负责人。' },
  'category.P.name': { en: 'Product Analytics', zh: '产品分析' },
  'category.P.desc': { en: 'Calculate funnel conversion, feature adoption, activation rate, stickiness (DAU/MAU), time-to-value, and power user curves for product managers at mid-market B2B SaaS companies ($10M-$50M ARR).', zh: '计算漏斗转化、功能采用率、激活率、用户粘性（DAU/MAU）、价值实现时间和重度用户曲线，适用于中型 B2B SaaS（$10M-$50M ARR）产品经理。' },
  'category.H.name': { en: 'Hiring & Team', zh: '招聘与团队' },
  'category.H.desc': { en: 'Calculate fully-loaded employee cost, ramp time, productivity ramp curves, compensation banding, equity refresh grants, and attrition cost for People-ops managers and Head-of-HR at mid-market B2B SaaS companies ($10M-$50M ARR).', zh: '计算全职员工成本、磨合期、生产力爬坡曲线、薪酬区间、股权刷新授予和离职成本，适用于中型 B2B SaaS（$10M-$50M ARR）的员工运营经理和人力资源负责人。' },
  'category.T.name': { en: 'Customer Support', zh: '客户支持' },
  'category.T.desc': { en: 'Calculate cost-per-support-ticket, first response time SLA, resolution time, CSAT, self-service deflection rate, and team capacity planning for CS Ops managers and Head-of-CS at mid-market B2B SaaS companies ($10M-$50M ARR).', zh: '计算单次支持工单成本、首次响应 SLA、解决时间、客户满意度、自助分流率和团队容量规划，适用于中型 B2B SaaS（$10M-$50M ARR）的客户支持运营经理和支持总监。' },
  'category.K.name': { en: 'Knowledge / 知识库', zh: '知识库' },
  'category.K.desc': { en: 'Calculate KB coverage rate, article freshness, search effectiveness, deflection quality, documentation ROI, and article helpfulness score for DevRel Leads, Documentation Managers, and Technical Writers at mid-market B2B SaaS companies ($10M-$50M ARR).', zh: '计算知识库覆盖率、文章新鲜度、搜索有效性、自助分流质量、文档 ROI 和文章有用性评分，适用于中型 B2B SaaS（$10M-$50M ARR）的开发者关系负责人、文档经理和技术写作人员。' },
  'category.L.name': { en: 'Legal & Compliance', zh: '法律与合规' },
  'category.L.desc': { en: 'Calculate GDPR fine risk, DSAR processing cost, cookie consent revenue impact, DPA negotiation cost, breach notification cost, and CMP platform ROI for DPOs, Privacy Officers, and Heads of Privacy at mid-market B2B SaaS companies ($10M-$50M ARR).', zh: '计算 GDPR 罚款风险、DSAR 处理成本、Cookie 同意收入影响、DPA 谈判成本、数据泄露通知成本和 CMP 平台 ROI，适用于中型 B2B SaaS（$10M-$50M ARR）的数据保护官、隐私官和隐私负责人。' },

