  // --- A5: Market Size Estimator ---
  'tools.solopreneur-market-size-estimator.title': { en: 'Market Size Estimator', zh: '市场规模估算器' },
  'tools.solopreneur-market-size-estimator.description': { en: 'Bottom-up market sizing: enter your target customers, pricing, and growth rate to estimate TAM, revenue potential, and what it takes to reach $100K.', zh: '自底向上估算市场规模：输入目标客户数、定价和增长率，估算TAM、收入潜力和达到$100K所需的条件。' },
  'tools.solopreneur-market-size-estimator.input.targetMarket.label': { en: 'Target Market', zh: '目标市场' },
  'tools.solopreneur-market-size-estimator.input.targetMarket.placeholder': { en: 'e.g. US dental clinics', zh: '例如：美国牙科诊所' },
  'tools.solopreneur-market-size-estimator.input.totalAddressableCustomers.label': { en: 'Total Addressable Customers', zh: '总可寻址客户数' },
  'tools.solopreneur-market-size-estimator.input.totalAddressableCustomers.placeholder': { en: 'e.g. 30000', zh: '例如：30000' },
  'tools.solopreneur-market-size-estimator.input.annualRevenuePerCustomer.label': { en: 'Avg Annual Revenue per Customer ($)', zh: '年均客单价 ($)' },
  'tools.solopreneur-market-size-estimator.input.annualRevenuePerCustomer.placeholder': { en: 'e.g. 5000', zh: '例如：5000' },
  'tools.solopreneur-market-size-estimator.input.marketGrowthRate.label': { en: 'Market Annual Growth Rate (%)', zh: '行业年增长率 (%)' },
  'tools.solopreneur-market-size-estimator.input.marketGrowthRate.placeholder': { en: 'e.g. 12', zh: '例如：12' },
  'tools.solopreneur-market-size-estimator.input.samPercent.label': { en: 'SAM — % of TAM You Can Reach', zh: 'SAM — 可触及的TAM百分比' },
  'tools.solopreneur-market-size-estimator.input.samPercent.placeholder': { en: 'e.g. 25', zh: '例如：25' },
  'tools.solopreneur-market-size-estimator.input.marketStage.label': { en: 'Market Stage', zh: '市场阶段' },
  'tools.solopreneur-market-size-estimator.input.marketStage.placeholder': { en: '', zh: '' },
  'tools.solopreneur-market-size-estimator.how_to_use.0': { en: 'Describe your target market (e.g., "US dental clinics", "SaaS startups").', zh: '描述你的目标市场（如"美国牙科诊所"、"SaaS创业公司"）。' },
  'tools.solopreneur-market-size-estimator.how_to_use.1': { en: 'Enter the total number of potential customers in your addressable market.', zh: '输入你可寻址市场中的潜在客户总数。' },
  'tools.solopreneur-market-size-estimator.how_to_use.2': { en: 'Enter your expected average annual revenue per customer.', zh: '输入你预期的年均客单价。' },
  'tools.solopreneur-market-size-estimator.how_to_use.3': { en: 'Enter the industry\'s annual growth rate (find this from industry reports).', zh: '输入行业年增长率（从行业报告中获取）。' },
  'tools.solopreneur-market-size-estimator.how_to_use.4': { en: 'Check the Market Overview for TAM and 3-5 year growth projections.', zh: '查看市场概览中的TAM和3-5年增长预测。' },
  'tools.solopreneur-market-size-estimator.how_to_use.5': { en: 'Scan the Revenue Potential table to see what different penetration rates yield.', zh: '浏览收入潜力矩阵，了解不同渗透率对应的收入。' },
  'tools.solopreneur-market-size-estimator.how_to_use.6': { en: 'Review the 3-Year Projection to see how compounding growth works in your favor.', zh: '查看3年增长预测，了解复利增长如何为你创造价值。' },
  'tools.solopreneur-market-size-estimator.how_to_use.7': { en: 'Read the Reality Check for a grounded assessment and your $100K target.', zh: '阅读现实检验，获取客观评估和$100K目标所需的客户数。' },
  'tools.solopreneur-market-size-estimator.faq.0.q': { en: 'What methodology does this calculator use?', zh: '这个计算器用什么方法？' },
  'tools.solopreneur-market-size-estimator.faq.0.a': { en: 'Bottom-up estimation: Total Addressable Customers × Average Revenue per Customer = TAM. This is the most practical method for solopreneurs because it ties directly to your business model — how many customers you can reach and what you can charge them. Top-down (starting from industry reports) is better for investor decks but less actionable for planning.', zh: '自底向上估算：总可寻址客户数 × 年均客单价 = TAM。这对独立开发者来说是最实用的方法，因为它直接与你的商业模式挂钩——你能触达多少客户、你能向他们收多少钱。自顶向下（从行业报告出发）更适合投资人演示，但对实际规划帮助较小。' },
  'tools.solopreneur-market-size-estimator.faq.1.q': { en: 'What is the difference between TAM, SAM, and SOM?', zh: 'TAM、SAM和SOM有什么区别？' },
  'tools.solopreneur-market-size-estimator.faq.1.a': { en: 'TAM (Total Addressable Market) is the total global demand — what this calculator estimates. SAM (Serviceable Addressable Market) is the portion you can realistically reach. SOM (Serviceable Obtainable Market) is what you can capture in the near term. The Revenue Potential section shows SOM at different penetration rates.', zh: 'TAM（总可寻址市场）是全球总需求——本计算器估算的就是这个。SAM（可服务可寻址市场）是你能实际触达的部分（如仅限说英语的用户、特定垂直领域）。SOM（可服务可获得市场）是短期内你能获取的份额。收入潜力矩阵展示了不同渗透率下的SOM。' },
  'tools.solopreneur-market-size-estimator.faq.2.q': { en: 'How do I find my total addressable customers number?', zh: '如何找到总可寻址客户数？' },
  'tools.solopreneur-market-size-estimator.faq.2.a': { en: 'Use Google + industry reports. For B2B: search "how many [business type] in [country]". For B2C: search "[demographic] population [country]". Examples: ~30,000 dental clinics in the US, ~5M software developers worldwide, ~20M small businesses in the US. Government census data, Statista, IBISWorld, and Gartner reports are good sources.', zh: '用谷歌和行业报告。B2B：搜索"[某地]有多少[某类企业]"（如"美国有多少牙科诊所"）。B2C：搜索"[某国][某人群]人口"。例子：美国约3万家牙科诊所、全球约500万软件开发者、美国约2000万小企业。政府人口普查数据、Statista、IBISWorld 和 Gartner 报告都是好的数据来源。' },
  'tools.solopreneur-market-size-estimator.faq.3.q': { en: 'What is a good market size for a solopreneur?', zh: '对独立开发者来说，多大规模的市场算好？' },
  'tools.solopreneur-market-size-estimator.faq.3.a': { en: 'A $100M-$1B TAM with 10%+ growth is excellent for a solopreneur. You only need 0.01-0.1% to reach $100K-$1M revenue. Markets under $50M can still work if you have high pricing ($5K+/customer) and can capture a significant share. Markets over $10B are great but watch for heavy competition.', zh: '1亿到10亿美元的TAM、年增长10%以上对独立开发者来说非常理想。你只需要0.01-0.1%的市场份额就能达到10万到100万美元的收入。低于5000万美元的市场，如果你定价高（每客户$5000+）且能拿下可观份额，仍然可行。超过100亿美元的市场很好，但要留意激烈竞争。' },
  'tools.solopreneur-market-size-estimator.faq.4.q': { en: 'How should I use the 3-year projection?', zh: '如何使用3年增长预测？' },
  'tools.solopreneur-market-size-estimator.faq.4.a': { en: "The projection assumes your market share doubles each year while the market itself grows. This is optimistic — treat it as an upside scenario. The base case is your Year 1 revenue number. If that number doesn't cover your living expenses, you need a larger starting share, higher pricing, or a bigger market.", zh: '预测假设你的市场份额每年翻倍，同时市场本身也在增长。这是乐观情景——当作上限来看。你的基础情景是第1年的收入数字。如果那个数字覆盖不了你的生活开支，你需要更大的起步份额、更高的定价或更大的市场。' },

